examples.original_ir:
define i8 @test(i8 %X, i8 %Y) {
  %shl = shl nsw i8 %X, 7
  %mul = mul i8 %Y, -128
  %srem = srem i8 %shl, %mul
  ret i8 %srem
}

examples.optimized_ir:
define i8 @test(i8 %X, i8 %Y) {
  %srem.unscaled = srem i8 %X, %Y
  %srem = mul nsw i8 %srem.unscaled, -128
  ret i8 %srem
}
